            <p id="popupMsg">Sei sicuro di rilanciare le build selezionate?</p>
            <div class="popup-actions">
                <button class="popup-cancel" onclick="closePopup()">Annulla</button>
                <button class="popup-confirm" onclick="executeRebuild()">Conferma</button>
